        function mockAsyncFunction(shouldError, callback) {
            setTimeout(() => {
                if (shouldError) {
                    callback(new Error('Test error'));
                } else {
                    callback(null, 'success');
                }
            }, 10);
        }

        const promisified = q.makePromise(mockAsyncFunction);

        promisified(true)
            .then(() => {
                done(new Error('Should have rejected'));
            })
            .catch(error => {
                assert.strictEqual(error.message, 'Test error');
                done();
            });
    });

    it('test q.makePromise with fallback function', function(done) {
        // Create a mock function that doesn't follow Node.js callback pattern
        function nonStandardFunction(value) {
            return value * 2;
        }

        function fallbackFunction(value) {
            return q.resolve(value * 3);
        }

        const promisified = q.makePromise(nonStandardFunction, fallbackFunction);

        promisified(4)
            .then(result => {
                assert.strictEqual(result, 12); // Should use fallback: 4 * 3
                done();
            })
            .catch(done);
    });

    it('test q.makePromise with multiple return values', function(done) {
        // Create a mock function that returns multiple values
        function mockAsyncFunction(callback) {
            setTimeout(() => {
                callback(null, 'first', 'second', 'third');
            }, 10);
        }

        const promisified = q.makePromise(mockAsyncFunction);

        promisified()
            .then(result => {
                // When multiple values are returned, only the first is typically used
                assert.strictEqual(result, 'first');
                done();
            })
            .catch(done);
    });

    it('test q.makePromise with no return value', function(done) {
        // Create a mock function that calls callback with no data
        function mockAsyncFunction(callback) {
            setTimeout(() => {
                callback(null);
            }, 10);
        }

        const promisified = q.makePromise(mockAsyncFunction);

        promisified()
            .then(result => {
                assert.strictEqual(result, undefined);
                done();
            })
            .catch(done);
    });
});
```

